sql:
SELECT customer_id, customer_name
FROM customers
WHERE customer_id NOT IN (SELECT customer_id FROM customer_feedback);

SELECT category_name, AVG(average_rating) AS avg_rating
FROM feedback_metrics
GROUP BY category_name;

SELECT category_name, average_rating
FROM feedback_metrics
WHERE category_id = 0;

SELECT AVG(average_rating) AS overall_avg_rating
FROM feedback_metrics
WHERE category_name = 'Mobile App';

SELECT DISTINCT u.user_name
FROM submission_logs sl
INNER JOIN users u ON sl.user_id = u.user_id;

SELECT category_name, average_rating 
FROM feedback_metrics 
ORDER BY average_rating DESC;

external_knowledge:
; The year 2022 refers to the period from January 1, 2022, to December 31, 2022; 
; Follow-up counts are determined by the presence of a follow-up action (is_followed_up = 1); 
; Submission logs refer to records of activities related to the feedback submissions.
